import React, { useState, useEffect } from 'react';
import './index.css';
import Sidebar from './components/Sidebar';
import Dashboard from './pages/Dashboard';
import Patients from './pages/Patients';
import Vaccinations from './pages/Vaccinations';
import Rappels from './pages/Rappels';
import Pharmacy from './pages/Pharmacy';
import Login from './pages/Login';

export default function App() {
  const [page, setPage] = useState('dashboard');
  const [selectedPatient, setSelectedPatient] = useState(null);
  const [isAuthenticated, setIsAuthenticated] = useState(false); // <--- ETAT D'AUTHENTIFICATION

  useEffect(() => {
    // Vérification basique d'une connexion persistante (pour la démo)
    const token = localStorage.getItem('vaccitrack_token');
    if (token) {
      setIsAuthenticated(true);
    }
  }, []);

  const handleLogout = () => {
    localStorage.removeItem('vaccitrack_token');
    localStorage.removeItem('vaccitrack_user');
    setIsAuthenticated(false);
  };

  const renderPage = () => {
    switch (page) {
      case 'dashboard': return <Dashboard setPage={setPage} />;
      case 'patients': return <Patients setPage={setPage} setSelectedPatient={setSelectedPatient} />;
      case 'vaccinations': return <Vaccinations selectedPatient={selectedPatient} setSelectedPatient={setSelectedPatient} />;
      case 'rappels': return <Rappels />;
      case 'pharmacy': return <Pharmacy />;
      default: return <Dashboard setPage={setPage} />;
    }
  };

  // Si non authentifié, on montre SEULEMENT l'écran de Login
  if (!isAuthenticated) {
    return <Login setAuthenticated={setIsAuthenticated} />;
  }

  // Sinon, on montre l'application normale
  return (
    <div className="app-layout">
      {/* On passe handleLogout si vous souhaitez ajouter un bouton de déconnexion dans la Sidebar ultérieurement */}
      <Sidebar page={page} setPage={setPage} />

      <main className="main-content">
        <header style={{ 
          display: 'flex', 
          justifyContent: 'space-between', 
          alignItems: 'center', 
          background: 'white', 
          padding: '12px 24px', 
          borderRadius: '16px', 
          marginBottom: '24px',
          boxShadow: '0 4px 15px rgba(0,0,0,0.03)',
          border: '1px solid #eaebef'
        }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
            <img src="/chu-logo.png" alt="CHU Tlemcen" style={{ height: '40px', width: 'auto' }} />
            <div style={{ height: '24px', width: '1px', background: '#eaebef' }}></div>
            <div>
              <div style={{ fontFamily: 'Syne', fontWeight: 800, fontSize: '13px', color: '#1d2129', textTransform: 'uppercase', letterSpacing: '0.5px' }}>
                CHU Tlemcen
              </div>
              <div style={{ fontSize: '11px', color: '#8a94a6', fontWeight: 600 }}>
                Service d'Épidémiologie et de Médecine Préventive
              </div>
            </div>
          </div>
          
          <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
            <div style={{ textAlign: 'right', marginRight: '8px' }}>
              <div style={{ fontSize: '12px', fontWeight: 700, color: '#1d2129' }}>Admin Session</div>
              <div style={{ fontSize: '10px', color: '#22c55e', fontWeight: 700 }}>● Connecté</div>
            </div>
            <button onClick={handleLogout} style={{ 
              background: '#fce7f3', 
              color: '#ec4899', 
              border: '1px solid #fbcfe8',
              padding: '8px 16px',
              borderRadius: '50px',
              fontSize: '12px',
              fontWeight: 700,
              cursor: 'pointer'
            }}>
              Déconnexion
            </button>
          </div>
        </header>
        {renderPage()}
      </main>
    </div>
  );
}
